var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000: <color=#ffd34c>유미나</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. FS007M0000：<color=#ffd34c>ヤナギ・ミナ</color>","ENG":"[[","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS007M0000: <color=#ffd34c>劉米娜</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เปิดทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข FS007M0000: <color=#ffd34c>ยู มีนา</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số. FS007M0000: <color=#ffd34c>Yoo Mina</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. FS007M0000: <color=#ffd34c>刘米娜</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. FS007M0000: <color=#ffd34c>Yoo Mina</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. FS007M0000\xA0: <color=#ffd34c>Yoo Mina</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"시각 독소라니...... 요즘도 이런 거창한 보안 절차를 쓰고 계셨군요.","JPN":"視覚毒素……、いまだにこんな大げさなセキュリティを使っているとは。","ENG":"Visual authentication? Still using this sort of extensive security protocol?","TWN":"居然是視覺毒素……您最近用的保全系統很優秀嘛。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"지시하신 대로 보안 회선 재구축을 마쳤습니다.","JPN":"指示通り、セキュリティ回線の再構築が終了しました。","ENG":"A secure line has been reconstructed as requested.","TWN":"根據您的指示，已經完成了安全線路的重建。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"앞으로는 이 회선을 통해 중요 사안을 보고드릴 예정입니다.","JPN":"今後は、こちらの回線を通して重要事項を報告する予定です。","ENG":"All crucial issues will be reported through this line from now on.","TWN":"以後將會透過該線路跟您彙報重要議題。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......사람들을 감시한다는 게 썩 즐거운 일은 아니지.","JPN":"……みんなを監視するというのは、さほど愉快なものではないな。","ENG":"It's not exactly an enjoyable experience to spy on people.","TWN":"……監視別人是一件不怎麼愉快的事情。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하지만 자네도 알다시피 중요한 일이니까 앞으로도 분발해 주게나.","JPN":"しかし君も知っているように、重要なことでもある。これからも頑張ってもらいたい。","ENG":"But as you know, this process is essential. Please continue to give it your best effort.","TWN":"但你也知道這件事的重要性，以後只能辛苦你了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"물론입니다. 상응하는 금액으로 보답해 주시기만 한다면 말이죠.","JPN":"もちろんです。それに見合う報酬をいただけるなら、最善を尽くしましょう。","ENG":"Of course. As long as I'm given the appropriate compensation.","TWN":"沒問題，只要您付出相應的金額就可以了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"크흠......! 크흠!","JPN":"コホン……！　コホン！","ENG":"Ahem! Ahem!","TWN":"咳咳……！咳咳！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그럼 일단 오늘의 보고 대상입니다.","JPN":"ではまず、本日の報告対象です。","ENG":"Anyway, here is the subject for today.","TWN":"這是今天要報告的對象。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"성명 유미나, 만 17세. 신장 168cm.","JPN":"ヤナギ・ミナ、満17歳。身長168㎝。","ENG":"Yoo Mina, 17 years old. Height, 168cm.","TWN":"劉米娜，17歲，身高168cm。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"관리국 카운터 등급평가 기준으로는 C 랭크입니다.","JPN":"管理局カウンターランク評価基準ではCランクです。","ENG":"Rated Grade C by the Administration Counter standards.","TWN":"以管理局制裁者的評價體系為基準的話，是C級。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"C 랭크라.......","JPN":"Cランクか……","ENG":"Grade C?","TWN":"C級……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 정도면 사실상 예비대 수준 아닌가?","JPN":"その程度なら、事実上予備隊レベルではないか？","ENG":"Isn't that about the same level as the reserves?","TWN":"這個水準的話，實際上只是個預備隊員的等級吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......예전 기준이라면 그렇겠죠.","JPN":"……以前の基準でしたらそうですね。","ENG":"Back in the day, yes.","TWN":"……按以前的標準來看，確實是這樣沒錯。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"최근에는 D 랭크도 충분히 업계 현역 대우입니다.","JPN":"最近はDランクでも十分、業界現役扱いです。","ENG":"But now, even Grade D Counters are being considered for active duty.","TWN":"但在最近，就算是D級也能有業界標準的待遇。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그것 참...... 인력난이 심각한가 보군.","JPN":"まったく……、深刻な人手不足だな。","ENG":"How unfortunate... We must be seriously lacking in manpower.","TWN":"這真是……看來最近人力短缺的問題很嚴重啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흐음...... 경력이 독특한데?","JPN":"うーん……独特な経歴を持っているな？","ENG":"Hmm... That's an unusual career history.","TWN":"嗯……履歷很特別呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};